};

scwin.gr_customerlist_oneditkeyup = function (info) {
    const inputEl = event.target;

    switch (info.colID) {
        case "clntNo" : 
            inputEl.value = info.newValue.toUpperCase();
            break;
        default :
            break;
    }
};
